package com.jc.recommendation.p2;
import com.jc.recommendation.p2.P2EvaluationContracts.Variant;import java.util.List;
public final class P2ExperimentAssigner { public Assignment assign(String experimentId,String experimentVersion,String subjectRef,int treatmentAllocationBasisPoints,String assignmentSalt){P2EvaluationContracts.requireIdentifier(experimentId,"experimentId");P2EvaluationContracts.requireIdentifier(experimentVersion,"experimentVersion");P2EvaluationContracts.requireIdentifier(subjectRef,"subjectRef");P2EvaluationContracts.requireIdentifier(assignmentSalt,"assignmentSalt");if(treatmentAllocationBasisPoints<0||treatmentAllocationBasisPoints>10000)throw new IllegalArgumentException("treatmentAllocationBasisPoints must be 0..10000");String material=experimentId+"|"+experimentVersion+"|"+subjectRef+"|"+assignmentSalt;String fingerprint=P2Canonical.sha256(List.of("p2-experiment-assignment-v1",material));int bucket=(int)(Long.parseUnsignedLong(fingerprint.substring(0,8),16)%10000L);Variant variant=bucket<treatmentAllocationBasisPoints?Variant.TREATMENT:Variant.BASELINE;return new Assignment("assignment:"+fingerprint.substring(0,48),experimentId,experimentVersion,subjectRef,variant,bucket,fingerprint);} public record Assignment(String assignmentId,String experimentId,String experimentVersion,String subjectRef,Variant variant,int bucket,String fingerprint){public Assignment{P2EvaluationContracts.requireIdentifier(assignmentId,"assignmentId");P2EvaluationContracts.requireIdentifier(experimentId,"experimentId");P2EvaluationContracts.requireIdentifier(experimentVersion,"experimentVersion");P2EvaluationContracts.requireIdentifier(subjectRef,"subjectRef");if(variant==null||bucket<0||bucket>=10000||fingerprint==null||!fingerprint.matches("[0-9a-f]{64}"))throw new IllegalArgumentException("invalid assignment");}}}
